// src/pages/ngo/user/RedeemPage.jsx
import { useState } from "react";
import { useToast } from "../../../context/ToastContext";
import PageHeader   from "../../../components/shared/PageHeader";
import { funds }    from "../../../data/mockData";
import { tokenApi } from "../../../services/api";

const fmt = (n) => n?.toLocaleString() ?? "–";
const allMyFunds = funds.filter((f) => f.ngo === "NGO001");

export default function RedeemPage() {
  const toast = useToast();
  const EMPTY = { userCert: "", tokenId: "", ngoId: "" };
  const [form, setForm] = useState(EMPTY);
  const [loading, setLoading] = useState(false);
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  const handleSubmit = async () => {
    if (!form.userCert || !form.tokenId || !form.ngoId) {
      toast("UserCert, token ID and NGO ID are required", "error");
      return;
    }

    setLoading(true);
    try {
      await tokenApi.redeem(form);
      toast("Redemption request submitted", "success");
      setForm((prev) => ({ ...EMPTY, userCert: prev.userCert, ngoId: prev.ngoId }));
    } catch (err) {
      toast(err?.response?.data?.error || err.message || "Redemption failed", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <PageHeader title="Redeem Tokens" desc="Convert fund tokens to fiat through an authorized bank" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group">
              <label>User Cert</label>
              <input value={form.userCert} onChange={upd("userCert")} placeholder="User certificate ID" />
            </div>
            <div className="form-group"><label>Token ID</label><input value={form.tokenId} onChange={upd("tokenId")} placeholder="e.g. token001" /></div>
            <div className="form-group"><label>NGO ID</label><input value={form.ngoId} onChange={upd("ngoId")} placeholder="e.g. NGO001" /></div>
            <div className="form-actions">
              <button className="btn btn-secondary" onClick={() => setForm((prev) => ({ ...EMPTY, userCert: prev.userCert, ngoId: prev.ngoId }))}>Clear</button>
              <button className="btn btn-primary" onClick={handleSubmit} disabled={loading}>{loading ? "Submitting..." : "Request Redemption ◈"}</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:4 }}>Token Balances by Fund</div>
          <div style={{ marginTop:14 }}>
            {allMyFunds.map((f) => (
              <div key={f.id} style={{ display:"flex", justifyContent:"space-between", padding:"12px 0", borderBottom:"1px solid var(--border)" }}>
                <span style={{ fontSize:13 }}>{f.name}</span>
                <span style={{ color:"var(--gold)", fontFamily:"'DM Mono',monospace", fontWeight:600 }}>◈ {fmt(f.raised)}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
